import (
	"fmt"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context. The script runs in a sandboxed environment
// with no access to unsafe system libraries to prevent malicious actions.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a sandboxed Lua state without loading default unsafe libraries
	L := lua.NewState(lua.Options{SkipOpenLibs: true})
	defer L.Close()

	// Optional: Uncomment to open safe libraries for common pricing calculations (e.g, math functions)
	// L.OpenLibs(lua.OpenMath)

	// Load and execute the user script
	if err := L.DoString(script); err!= nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type()!= lua.LTFunction {
		L.Pop(1) // Clean up stack before returning error
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}
	L.Pop(1) // Remove function from stack as we already hold a reference

	// Convert Go context map to Lua table (pushes table to stack)
	ctxTable := L.NewTable()
	for k, v := range ctx {
		// Use -1 as the stack index of the newly created table
		L.SetField(-1, k, lua.LNumber(v))
	}
	L.Pop(1) // Remove table from stack since CallByParam will push it again

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err!= nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Validate and convert result to float64
	if result.Type()!= lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	return float64(result.(lua.LNumber)), nil
}

