package main

import (
	"fmt"
	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with no preloaded standard libraries for security
	L := lua.NewState(lua.Options{SkipOpenLibs: true})
	defer L.Close()

	// Load and execute the script
	if err := L.DoString(script); err != nil {
		// Pop error object left on stack by failed DoString
		L.Pop(1)
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope (pushes value to stack)
	L.GetGlobal("calculate_final_price")
	if L.Get(-1).Type()!= lua.LTFunction {
		// Pop non-function value before returning error
		L.Pop(1)
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table (pushes new table to stack)
	L.NewTable()
	for k, v := range ctx {
		// Set field on the newly created table (currently at top of stack)
		L.SetField(L.Get(-1), k, lua.LNumber(v))
	}

	// Call the function: stack contains [function, context table], 1 argument, 1 return value
	if err := L.PCall(1, 1, nil); err != nil {
		// Pop error object left on stack by failed protected call
		L.Pop(1)
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	// Remove the result from the stack to balance the stack
	L.Pop(1)

	// Convert result to float64
	if result.Type()!= lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	return float64(result.(lua.LNumber)), nil
}

// Optional main function for testing the implementation
