package main

import (
	"fmt"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create Lua state with no preloaded libraries to avoid exposing dangerous functionality
	L := lua.NewState(lua.Options{SkipOpenLibs: true})
	defer L.Close()

	// Open only minimal safe standard libraries
	lua.OpenBase(L)
	lua.OpenMath(L) // Include math library for common pricing calculations

	// Create isolated sandbox environment for user script
	sandbox := L.NewTable()

	// Whitelist only safe base library functions (exclude unsafe operations like load/getfenv)
	allowedGlobals := []string{
		"assert", "error", "ipairs", "pairs", "next",
		"pcall", "select", "tonumber", "tostring", "type", "xpcall",
	}
	for _, name := range allowedGlobals {
		val := L.GetGlobal(name)
		sandbox.RawSetString(name, val)
	}

	// Expose math library to sandbox
	sandbox.RawSetString("math", L.GetGlobal("math"))

	// Point sandbox _G to itself to prevent access to real global scope
	sandbox.RawSetString("_G", sandbox)

	// Configure instruction limit to prevent infinite loops and DoS attacks
	const maxInstructions = 10000
	instructionCount := 0
	L.SetHook(func(L *lua.LState) int {
		instructionCount++
		if instructionCount > maxInstructions {
			L.RaiseError("script exceeded maximum instruction limit of %d", maxInstructions)
		}
		return 0
	}, lua.HookCountMask, 1) // Trigger hook every instruction for accurate counting

	// Load user script without executing
	scriptFn, err := L.LoadString(script)
	if err != nil {
		return 0, fmt.Errorf("failed to load Lua script: %w", err)
	}

	// Set script environment to the sandbox
	L.Push(scriptFn)
	L.Push(sandbox)
	fn := L.Get(-2)
	env := L.Get(-1)
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("failed to set script execution environment")
	}
	L.SetFEnv(fn, env)
	L.Pop(1) // Pop sandbox from stack, leaving scriptFn at top

	// Execute script to define functions in the sandbox
	if err := L.PCall(0, 0, nil); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get calculate_final_price from the sandbox (not global scope)
	fnVal := L.GetField(sandbox, "calculate_final_price")
	if fnVal.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the pricing function in protected mode
	if err := L.CallByParam(lua.P{
		Fn:      fnVal,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Process and validate result
	result := L.Get(-1)
	L.Pop(1)

	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	return float64(result.(lua.LNumber)), nil
}

