func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Initialize Lua virtual machine
	L := lua.NewState()
	defer L.Close()

	// Load and execute the user-provided script to define the calculate_final_price function
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("script execution failed: %w", err)
