	if calculateFn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("global 'calculate_final_price' is not a function, got type %s", calculateFn.Type())
	}

	// Convert the Go context map to a Lua table
	ctxTable := L.NewTable()
	for key, value := range ctx {
		L.SetField(ctxTable, key, lua.LNumber(value))
	}

	// Push the context table as the function argument
	L.Push(ctxTable)

