// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with no preloaded libraries
	L := lua.NewState()
	defer L.Close()

	// Open base library then restrict to only safe functions to exclude dangerous ones like load/setmetatable
	lua.OpenBase(L)
	allowedBaseFuncs := map[string]bool{
		"pairs":    true,
		"ipairs":   true,
		"type":     true,
		"tonumber": true,
		"tostring": true,
		"error":    true,
		"assert":   true,
	}
	globals := L.Get(lua.GlobalsIndex).(*lua.LTable)
	globals.ForEach(func(k, v lua.LValue) {
		if key, ok := k.(lua.LString); ok {
			if!allowedBaseFuncs[string(key)] {
				globals.RawSet(k, lua.LNil)
			}
		}
	})

	// Load the safe math library for arithmetic operations
	lua.OpenMath(L)

	// Set up context with timeout to prevent infinite loops and DoS attacks
	execCtx, cancel := context.WithTimeout(context.Background(), scriptTimeout)
	defer cancel()
	L.SetContext(execCtx)

	// Load the user script (catches syntax errors)
	scriptFn, err := L.Load(strings.NewReader(script), "pricing_script", "t")
	if err!= nil {
		return 0, fmt.Errorf("script syntax error: %w", err)
	}

	// Create isolated sandbox environment for the script
	sandbox := L.NewTable()
	sandboxMeta := L.NewTable()
	// Allow access to safe global functions via __index lookup
	sandboxMeta.RawSet(lua.LString("__index"), L.Get(lua.GlobalsIndex))
	// Protect sandbox metatable from access/modification by the script
	sandboxMeta.RawSet(lua.LString("__metatable"), lua.LString("sandbox metatable is protected"))
	L.SetMetatable(sandbox, sandboxMeta)

	// Assign the sandbox as the script's environment
	if!lua.SetFenv(L, scriptFn, sandbox) {
		return 0, fmt.Errorf("failed to configure script sandbox")
	}

	// Push script function to stack for execution
	L.Push(scriptFn)

	// Execute the script in protected mode to catch runtime errors
	if err := L.PCall(0, 0, nil); err!= nil {
		return 0, fmt.Errorf("script execution failed: %w", err)
	}

	// Retrieve the pricing function from the sandbox
	calcFn := sandbox.RawGet(lua.LString("calculate_final_price"))
	if calcFn.Type()!= lua.LTFunction {
		return 0, fmt.Errorf("script does not export a calculate_final_price function")
	}

	// Convert context map to read-only Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		ctxTable.RawSet(lua.LString(k), lua.LNumber(v))
	}

	// Enforce read-only behavior for context table
	ctxMeta := L.NewTable()
	ctxMeta.RawSet(lua.LString("__newindex"), L.NewFunction(func(L *lua.LState) int {
		L.RaiseError("modification of context table is not allowed")
		return 0
	}))
	// Protect context metatable from access/modification
	ctxMeta.RawSet(lua.LString("__metatable"), lua.LString("context metatable is protected"))
	L.SetMetatable(ctxTable, ctxMeta)

	// Call the pricing function in protected mode
	if err := L.CallByParam(lua.P{
		Fn:      calcFn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err!= nil {
		return 0, fmt.Errorf("calculate_final_price execution failed: %w", err)
	}

	// Retrieve and validate the result
	result := L.Get(-1)
	L.Pop(1) // Clean up the stack
	if result.Type()!= lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price returned a non-numeric value")
	}

	return float64(result.(lua.LNumber)), nil
}

