const (
	// maxCallStack limits function call depth to prevent stack overflow from deep recursion
	maxCallStack = 64
	// maxRegistrySize sets initial registry size to limit excessive object creation
	maxRegistrySize = 1024
	// maxInstructions limits VM execution steps to prevent infinite loops and DoS
	maxInstructions = 10000
)
// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context, with security sandboxing for untrusted code.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create sandboxed Lua state with restricted resources and safe libraries only
	L := lua.NewState(lua.Options{
		CallStackSize: maxCallStack,
		RegistrySize:  maxRegistrySize,
	})
	defer L.Close()
	// Load only minimal safe standard libraries
	lua.OpenBase(L) // Core language features
	lua.OpenMath(L) // Arithmetic functions for pricing calculations
	// Remove all unsafe functions and libraries from global scope
	unsafeGlobals := []string{
		// Code loading/execution functions
		"dofile", "loadfile", "load", "loadstring", "require",
		// System interaction libraries
		"package", "io", "os", "debug",
		// Side-effect functions
		"print", "collectgarbage",
		// Low-level functions that bypass metatable protections
		"rawget", "rawset", "rawequal", "rawlen",
	}
	for _, name := range unsafeGlobals {
		L.SetGlobal(name, lua.LNil)
	}
	// Set instruction limit hook to terminate long-running scripts
	L.SetHook(func(L *lua.LState, ar *lua.Debug) int {
		L.RaiseError("script exceeded maximum instruction limit of %d (possible infinite loop)", maxInstructions)
		return 0
	}, lua.HookMaskCount, maxInstructions)
	// Load and execute the user script in the sandboxed environment
	if err := L.DoString(script); err!= nil {
		return 0, fmt.Errorf("failed to load script: %w", err)
	}
	// Validate the required calculate_final_price function exists
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type()!= lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}
	// Convert context map to read-only Lua table to prevent modification
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}
	// Create metatable to enforce read-only access
	ctxMT := L.NewTable()
	L.SetField(ctxMT, "__newindex", L.NewFunction(func(L *lua.LState) int {
		L.RaiseError("attempt to modify read-only context table")
		return 0
	}))
	// Protect metatable to prevent tampering with read-only restrictions
	L.SetField(ctxMT, "__metatable", lua.LString("context metatable is protected"))
	L.SetMetatable(ctxTable, ctxMT)
	// Execute the pricing function with the context
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true, // Catch errors instead of panicking
	}, ctxTable); err!= nil {
		return 0, fmt.Errorf("failed to execute calculate_final_price: %w", err)
	}
	// Retrieve and validate the result
	result := L.Get(-1)
	L.Pop(1) // Clean up stack
	if result.Type()!= lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price returned non-numeric value: %s", result.Type().String())
	}
	return float64(result.(lua.LNumber)), nil
}

