// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new isolated Lua state
	L := lua.NewState()

	// Load only safe standard libraries (base for core utilities, math for calculations)
	L.OpenBase()
	L.OpenMath()

	// Remove dangerous global functions to prevent code injection, unsafe operations, and information leakage
	dangerousFuncs := []string{
		"load", "loadstring", "loadfile", "dofile", // Code loading functions
		"require", "module", // Module loading functions
		"getfenv", "setfenv", // Environment manipulation
		"setmetatable", "getmetatable", // Metatable manipulation
		"rawget", "rawset", "rawequal", // Raw access bypassing metatables
		"print", // Prevent log spamming/information leakage
	}
	for _, fn := range dangerousFuncs {
		L.SetGlobal(fn, lua.LNil)
	}

	// Configure timeout to prevent infinite loops and resource exhaustion
	const scriptTimeout = 500 * time.Millisecond
	execCtx, cancel := context.WithTimeout(context.Background(), scriptTimeout)
	defer cancel()

	type result struct {
		price float64
		err   error
	}
	resChan := make(chan result, 1)

	go func() {
		defer L.Close()
		defer func() {
			if r := recover(); r!= nil {
				resChan <- result{0, fmt.Errorf("script execution panicked: %v", r)}
			}
		}()

		// Load and execute the user script's top-level code (protected call to catch errors)
		if err := L.DoString(script); err!= nil {
			resChan <- result{0, fmt.Errorf("failed to execute Lua script: %w", err)}
			return
		}

		// Verify the required function exists and is a valid function
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type()!= lua.LTFunction {
			resChan <- result{0, fmt.Errorf("calculate_final_price is not a function or not defined")}
			return
		}

		// Convert Go context map to an internal Lua table (not exposed directly to the script)
		actualCtx := L.NewTable()
		for k, v := range ctx {
			L.SetField(actualCtx, k, lua.LNumber(v))
		}

		// Create a read-only proxy table to pass to the script (prevents modification of input context)
		ctxTable := L.NewTable()
		ctxMeta := L.NewTable()
		// Forward read operations to the internal context table
		L.SetField(ctxMeta, "__index", actualCtx)
		// Block all write operations to the context
		L.SetField(ctxMeta, "__newindex", L.NewFunction(func(l *lua.LState) int {
			l.RaiseError("context table is read-only; modifications are not allowed")
			return 0
		}))
		// Protect the metatable from access (extra security layer)
		L.SetField(ctxMeta, "__metatable", lua.LString("context metatable is protected"))
		L.SetMetatable(ctxTable, ctxMeta)

		// Call the calculate_final_price function with the read-only context (protected call)
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err!= nil {
			resChan <- result{0, fmt.Errorf("failed to call calculate_final_price: %w", err)}
			return
		}

		// Retrieve and validate the result
		resVal := L.Get(-1)
		L.Pop(1) // Clean up the stack

		if resVal.Type()!= lua.LTNumber {
			resChan <- result{0, fmt.Errorf("calculate_final_price did not return a number")}
			return
		}

		res := float64(resVal.(lua.LNumber))
		// Validate result is a valid, non-negative price
		if math.IsNaN(res) || math.IsInf(res, 0) {
			resChan <- result{0, fmt.Errorf("calculate_final_price returned invalid non-finite value: %f", res)}
			return
		}
		if res < 0 {
			resChan <- result{0, fmt.Errorf("calculate_final_price returned negative price: %f", res)}
			return
		}

		resChan <- result{res, nil}
	}()

	// Wait for either the result or the timeout
	select {
	case <-execCtx.Done():
		return 0, fmt.Errorf("script execution timed out after %v", scriptTimeout)
	case res := <-resChan:
		return res.price, res.err
	}
}

